async function main(args) {
  const phone = (args.transcript || "").match(/\b\d{3}[\s.-]?\d{3}[\s.-]?\d{4}\b/g);
  if (phone && phone.length > 0) {
    const cleaned = phone[phone.length - 1].replace(/[\s.-]/g, "");
    const formatted = `(${cleaned.slice(0,3)}) ${cleaned.slice(3,6)}-${cleaned.slice(6)}`;
    return { phone_captured: formatted, phone_raw: cleaned };
  }
  return { phone_captured: "none", phone_raw: "" };
}
